import { MAX_ERROR_HISTORY } from '@/shared/constants';
import type { RecoveryOption } from '@/shared/types';

import { type ErrorCode, ErrorCodes, getErrorMessage } from './ErrorCodes';
import { getEventBus } from './EventBus';

export { type RecoveryOption };

export class ErrorHandler implements ErrorHandlerContract {
  private static instance: ErrorHandler | null = null;
  private fatalCallbacks = new Set<(error: AppError) => void>();
  private history: AppError[] = [];
  private maxHistory = MAX_ERROR_HISTORY;
  private disposed = false;

  static getInstance(): ErrorHandler {
    ErrorHandler.instance ??= new ErrorHandler();

    return ErrorHandler.instance;
  }

  static resetInstance(): void {
    if (ErrorHandler.instance) {
      ErrorHandler.instance.dispose();
    }
    ErrorHandler.instance = null;
  }

  private categorizeSeverity(error: Error): ErrorSeverity {
    const message = error.message.toLowerCase();

    if (message.includes('fatal') || message.includes('critical')) {
      return ErrorSeverity.FATAL;
    }
    if (message.includes('warning') || message.includes('deprecated')) {
      return ErrorSeverity.WARNING;
    }
    if (message.includes('info') || message.includes('notice')) {
      return ErrorSeverity.INFO;
    }

    return ErrorSeverity.ERROR;
  }

  clearHistory(): void {
    if (this.disposed) {
      console.warn('ErrorHandler already disposed');
      return;
    }
    this.history = [];
  }

  createCodedError(code: ErrorCode, context: string, originalError?: Error): AppError {
    const recoveryOptions = this.suggestRecovery(
      originalError ?? new Error(getErrorMessage(code)),
      ErrorSeverity.ERROR
    );

    return this.createError(code, getErrorMessage(code), {
      context,
      ...(originalError ? { originalError } : {}),
      ...(recoveryOptions ? { recoveryOptions } : {}),
    });
  }

  createError(code: string, message: string, options?: Partial<AppError>): AppError {
    if (this.disposed) {
      console.warn('ErrorHandler has been disposed, cannot create new error');
      return {
        code: 'DISPOSED',
        message: 'ErrorHandler has been disposed',
        severity: ErrorSeverity.ERROR,
        context: 'disposed',
        timestamp: Date.now(),
        recoverable: false,
      };
    }

    return {
      code,
      message,
      severity: options?.severity ?? ErrorSeverity.ERROR,
      context: options?.context ?? 'unknown',
      timestamp: Date.now(),
      recoverable: options?.recoverable ?? true,
      ...(options?.recoveryOptions ? { recoveryOptions: options.recoveryOptions } : {}),
      ...(options?.originalError ? { originalError: options.originalError } : {}),
    };
  }

  private emitEvent(error: AppError): void {
    try {
      const eventType = error.severity === ErrorSeverity.FATAL ? 'error:fatal' : 'error:occurred';

      getEventBus().emit(eventType, {
        type: error.code,
        message: error.message,
        context: { severity: error.severity, recoverable: error.recoverable },
      });
    } catch {
      // 避免事件总线错误导致二次崩溃
      console.error('Failed to emit error event:', error);
    }
  }

  private extractErrorCode(error: Error): ErrorCode | null {
    const match = error.message.match(/^(E\d{3})/);

    if (match?.[1]) {
      const code = match[1] as ErrorCode;

      if (Object.values(ErrorCodes).includes(code)) {
        return code;
      }
    }

    return null;
  }

  /** 获取错误历史记录的只读副本 */
  getHistory(): AppError[] {
    return [...this.history];
  }

  handle(error: Error | AppError, context?: { context?: string }): AppError {
    if (this.disposed) {
      console.warn('ErrorHandler has been disposed, error not recorded:', error);
      return this.createError('DISPOSED', 'ErrorHandler disposed', { ...(context?.context ? { context: context.context } : {}) });
    }

    const appError = this.normalizeError(error, context?.context);

    this.recordError(appError);
    this.emitEvent(appError);

    if (appError.severity === ErrorSeverity.FATAL) {
      this.notifyFatalCallbacks(appError);
    }

    return appError;
  }

  private isAppError(error: unknown): error is AppError {
    return (
      typeof error === 'object' &&
      error !== null &&
      'code' in error &&
      'severity' in error &&
      'timestamp' in error
    );
  }

  private normalizeError(error: Error | AppError, context?: string): AppError {
    if (this.isAppError(error)) {
      return error;
    }

    const severity = this.categorizeSeverity(error);

    const recoveryOptions = this.suggestRecovery(error, severity);

    return {
      code: error.name || 'UNKNOWN_ERROR',
      message: error.message,
      severity,
      context: context ?? 'unknown',
      timestamp: Date.now(),
      recoverable: severity !== ErrorSeverity.FATAL,
      ...(recoveryOptions ? { recoveryOptions } : {}),
      originalError: error as Error,
    } as AppError;
  }

  private notifyFatalCallbacks(error: AppError): void {
    for (const callback of this.fatalCallbacks) {
      try {
        callback(error);
      } catch (err) {
        console.error('Fatal callback error:', err);
      }
    }
  }

  onFatalError(callback: (error: AppError) => void): () => void {
    if (this.disposed) {
      console.warn('Adding fatal callback to disposed ErrorHandler');
      return () => {};
    }

    this.fatalCallbacks.add(callback);

    return () => this.fatalCallbacks.delete(callback);
  }

  private recordError(error: AppError): void {
    this.history.push(error);
    if (this.history.length > this.maxHistory) {
      // 只保留最近的错误历史
      this.history = this.history.slice(-this.maxHistory);
    }
  }

  private suggestRecovery(error: Error, severity: ErrorSeverity): RecoveryOption[] | undefined {
    const code = this.extractErrorCode(error);
    const message = error.message.toLowerCase();

    // Handle TensorFlow specific errors
    if (message.includes('tensorflow') || message.includes('model load timeout')) {
      return [
        {
          label: '使用云端AI模式',
          action: () => {
            try {
              getEventBus().emit('ai:switch-to-gemini', {});
            } catch {
              console.warn('Failed to switch to Gemini AI mode');
            }
          },
        },
        {
          label: '重试加载',
          action: () => {
            try {
              getEventBus().emit('ai:retry-tensorflow', {});
            } catch {
              console.warn('Failed to retry TensorFlow loading');
            }
          },
        },
      ];
    }

    if (code) {
      switch (code) {
        case ErrorCodes.ASSET_LOAD_FAILED:
        case ErrorCodes.ASSET_INVALID:
          return [
            {
              label: '重试加载',
              action: () => {
                try {
                  getEventBus().emit('asset:retry', {});
                } catch {
                  console.warn('Failed to retry asset loading');
                }
              },
            },
            {
              label: '选择其他文件',
              action: () => {
                try {
                  getEventBus().emit('ui:open-upload', {});
                } catch {
                  console.warn('Failed to open upload dialog');
                }
              },
            },
          ];
        case ErrorCodes.ASSET_TOO_LARGE:
          return [
            {
              label: '选择较小文件',
              action: () => {
                try {
                  getEventBus().emit('ui:open-upload', {});
                } catch {
                  console.warn('Failed to open upload dialog');
                }
              },
            },
          ];
        case ErrorCodes.SERVICE_NOT_READY:
        case ErrorCodes.INIT_FAILED:
          return [
            {
              label: '重新初始化',
              action: () => {
                window.location.reload();
              },
            },
          ];
        case ErrorCodes.AI_MODEL_LOAD_FAILED:
        case ErrorCodes.AI_INFERENCE_FAILED:
          return [
            {
              label: '重试AI处理',
              action: () => {
                try {
                  getEventBus().emit('ai:retry', {});
                } catch {
                  console.warn('Failed to retry AI processing');
                }
              },
            },
            {
              label: '跳过AI处理',
              action: () => {
                try {
                  getEventBus().emit('ai:skip', {});
                } catch {
                  console.warn('Failed to skip AI processing');
                }
              },
            },
          ];
      }
    }

    if (severity === ErrorSeverity.FATAL) {
      return [
        {
          label: '刷新页面',
          action: () => {
            window.location.reload();
          },
        },
      ];
    }
    if (severity === ErrorSeverity.ERROR) {
      return [{ label: '重试', action: () => {} }];
    }

    return undefined;
  }

  /** 释放 ErrorHandler 资源 */
  dispose(): void {
    if (this.disposed) {
      return;
    }

    this.disposed = true;
    this.fatalCallbacks.clear();
    this.history = [];
    ErrorHandler.instance = null;

    console.info('ErrorHandler disposed');
  }

  /** 检查是否已释放 */
  isDisposed(): boolean {
    return this.disposed;
  }
}

export interface AppError {
  code: string;
  context: string;
  message: string;
  originalError?: Error;
  recoverable: boolean;
  recoveryOptions?: RecoveryOption[];
  severity: ErrorSeverity;
  timestamp: number;
}
export interface ErrorHandlerContract {
  clearHistory(): void;
  createError(code: string, message: string, options?: Partial<AppError>): AppError;
  getHistory(): AppError[];
  handle(error: Error | AppError, context?: { context?: string }): AppError;
  onFatalError(callback: (error: AppError) => void): () => void;
  dispose(): void;
  isDisposed(): boolean;
}

export enum ErrorSeverity {
  ERROR = 'error',
  FATAL = 'fatal',
  INFO = 'info',
  WARNING = 'warning',
}

export const getErrorHandler = (): ErrorHandlerContract => ErrorHandler.getInstance();
export const resetErrorHandler = (): void => {
  ErrorHandler.resetInstance();
};

import { createLogger } from '@/core/Logger';
import type { Disposable } from '@/shared/types';
import { generateUUID } from '@/shared/utils/uuid';

export interface WorkerTask<T = unknown> {
  id: string;
  payload: T;
  transfer?: Transferable[];
  type: string;
}

export interface WorkerResponse<R = unknown> {
  error?: string;
  id: string;
  payload?: R;
  success: boolean;
}

const logger = createLogger({ module: 'WorkerManager' });

const FALLBACK_POOL_SIZE = 4;
const DEFAULT_POOL_SIZE =
  typeof navigator !== 'undefined'
    ? navigator.hardwareConcurrency || FALLBACK_POOL_SIZE
    : FALLBACK_POOL_SIZE;

let workerManagerInstance: WorkerManager | null = null;

export class WorkerManager implements Disposable {
  private pendingTasks = new Map<
    string,
    { reject: (reason: unknown) => void; resolve: (value: unknown) => void }
  >();
  private poolSize: number;
  private workerPools = new Map<string, Worker[]>();
  private workerRoundRobin = new Map<string, number>();
  private disposed = false;

  constructor(poolSize: number = DEFAULT_POOL_SIZE) {
    this.poolSize = poolSize;
  }

  static getInstance(): WorkerManager {
    workerManagerInstance ??= new WorkerManager();

    return workerManagerInstance;
  }

  private createWorker(name: string): Worker {
    const workerUrl = new URL(`./${name}.worker.ts`, import.meta.url);
    const worker = new Worker(workerUrl, { type: 'module' });

    worker.onmessage = (event: MessageEvent<WorkerResponse>) => {
      const { id, success, payload, error } = event.data;
      const task = this.pendingTasks.get(id);

      if (task) {
        if (success) {
          task.resolve(payload);
        } else {
          task.reject(new Error(error));
        }
        this.pendingTasks.delete(id);
      }
    };

    worker.onerror = (error) => {
      logger.error(`Worker error in ${name}`, { error: String(error) });
    };

    return worker;
  }

  async dispose(): Promise<void> {
    if (this.disposed) {
      logger.warn('WorkerManager already disposed');
      return;
    }

    this.disposed = true;
    const errors: Error[] = [];

    for (const [name, pool] of this.workerPools) {
      for (const worker of pool) {
        try {
          worker.terminate();
        } catch (error) {
          errors.push(error as Error);
        }
      }
      logger.info(`Terminated ${pool.length} workers for: ${name}`);
    }

    this.workerPools.clear();
    this.pendingTasks.clear();
    workerManagerInstance = null;

    if (errors.length > 0) {
      logger.error('Some workers failed to terminate', { errors });
    }

    logger.info('WorkerManager disposed');
  }

  execute<T, R>(
    workerName: string,
    taskType: string,
    payload: T,
    transfer?: Transferable[]
  ): Promise<R> {
    if (this.disposed) {
      return Promise.reject(new Error('WorkerManager has been disposed'));
    }

    const taskId = generateUUID();

    return new Promise<R>((resolve, reject) => {
      this.pendingTasks.set(taskId, { resolve: resolve as (v: unknown) => void, reject });

      const message: WorkerTask<T> = {
        id: taskId,
        payload,
        ...(transfer ? { transfer } : {}),
        type: taskType,
      };

      const worker = this.getNextWorker(workerName);

      try {
        worker.postMessage(message, transfer ?? []);
      } catch (error) {
        this.pendingTasks.delete(taskId);
        reject(error);
      }
    });
  }

  private getNextWorker(name: string): Worker {
    if (!this.workerPools.has(name)) {
      this.warmupPool(name);
    }

    const pool = this.workerPools.get(name)!;
    const currentIndex = this.workerRoundRobin.get(name) ?? 0;
    const worker = pool[currentIndex % pool.length]!;

    this.workerRoundRobin.set(name, currentIndex + 1);

    return worker;
  }

  warmupPool(name: string): void {
    if (this.workerPools.has(name)) {
      return;
    }

    const pool: Worker[] = [];

    try {
      for (let i = 0; i < this.poolSize; i++) {
        const worker = this.createWorker(name);
        pool.push(worker);
      }
    } catch (error) {
      // 清理已创建的 worker
      pool.forEach((w) => w.terminate());
      logger.error(`Failed to warm up pool for ${name}`, { error });
      throw error;
    }

    this.workerPools.set(name, pool);
    this.workerRoundRobin.set(name, 0);
    logger.info(`Warmed up pool for ${name} with ${this.poolSize} workers`);
  }

  /** 获取指定 worker pool 的状态信息 */
  getPoolStatus(name: string): { workerCount: number; pendingTasks: number } | null {
    const pool = this.workerPools.get(name);
    if (!pool) return null;

    return {
      workerCount: pool.length,
      pendingTasks: this.pendingTasks.size,
    };
  }
}

export function getWorkerManager(): WorkerManager {
  return WorkerManager.getInstance();
}

import { memo, useEffect, useRef, useState } from 'react';

import { useServices } from '@/core/contexts/ServiceContext';

interface ProgressState {
  isProcessing: boolean;
  message: string;
  progress: number;
  stage: string;
}

const STAGE_MESSAGES: Record<string, string> = {
  analyzing: 'AI场景分析中',
  depth_estimation: '深度图生成中',
  initializing: '初始化中',
  loading: '模型加载中',
  processing: '处理中',
};

const STAGE_EMOJIS: Record<string, string> = {
  analyzing: '🔍',
  depth_estimation: '📊',
  initializing: '⚙️',
  loading: '📦',
  processing: '⚡',
};

export const AIProgressPanel = memo(() => {
  const { aiService } = useServices();
  const [progress, setProgress] = useState<ProgressState>({
    stage: '',
    progress: 0,
    isProcessing: false,
    message: '',
  });
  const [isVisible, setIsVisible] = useState(false);
  const hideTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    if (!aiService) return;

    const unsubscribe = aiService.onProgress((p, stage) => {
      const isProcessing = p < 100 && p > 0;

      setProgress({
        stage,
        progress: p,
        isProcessing,
        message: STAGE_MESSAGES[stage] || stage,
      });

      setIsVisible(isProcessing || p === 100);

      if (p === 100) {
        if (hideTimerRef.current) {
          clearTimeout(hideTimerRef.current);
        }
        hideTimerRef.current = setTimeout(() => setIsVisible(false), 3000);
      }
    });

    return () => {
      unsubscribe();
      if (hideTimerRef.current) {
        clearTimeout(hideTimerRef.current);
      }
    };
  }, [aiService]);

  if (!isVisible) return null;

  const emoji = STAGE_EMOJIS[progress.stage] || '🤖';

  return (
    <div className="bg-slate-900/80 backdrop-blur-md rounded-lg p-4 border border-slate-300/50 shadow-xl">
      <div className="flex items-center gap-3 mb-3">
        <span className="text-2xl animate-pulse">{emoji}</span>
        <div className="flex-1">
          <div className="flex items-center justify-between mb-1">
            <span className="text-sm font-medium text-slate-800">{progress.message}</span>
            <span className="text-xs text-slate-400">{Math.round(progress.progress)}%</span>
          </div>
          <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
            <div
              className="h-full bg-gradient-to-r from-blue-500 via-purple-500 to-pink-500 transition-all duration-300 ease-out"
              style={{ width: `${progress.progress}%` }}
            >
              <div className="w-full h-full animate-pulse bg-white/20" />
            </div>
          </div>
        </div>
      </div>

      <div className="flex items-center justify-between text-xs">
        <div className="flex gap-3">
          <span className={`${progress.progress > 0 ? 'text-blue-400' : 'text-slate-500'}`}>
            ● 准备
          </span>
          <span className={`${progress.progress >= 30 ? 'text-purple-400' : 'text-slate-500'}`}>
            ● 处理
          </span>
          <span className={`${progress.progress >= 70 ? 'text-pink-400' : 'text-slate-500'}`}>
            ● 优化
          </span>
          <span className={`${progress.progress === 100 ? 'text-green-400' : 'text-slate-500'}`}>
            ● 完成
          </span>
        </div>

        {progress.progress === 100 && (
          <span className="text-green-400 animate-pulse">✓ 处理完成</span>
        )}
      </div>
    </div>
  );
});

AIProgressPanel.displayName = 'AIProgressPanel';

import type { CameraPose, MotionParams, MotionResult, Vec3 } from '@/shared/types';

export { MotionParams, MotionResult } from '@/shared/types';

export type MotionType =
  | 'ORBIT'
  | 'ARC'
  | 'DOLLY_ZOOM'
  | 'FLY_BY'
  | 'SPIRAL'
  | 'TRACKING'
  | 'STATIC';

export const DEFAULT_MOTION_PARAMS: MotionParams = {
  arcAngle: 90,
  arcRhythm: 1,
  dollyIntensity: 0.8,
  dollyRange: 10,
  flyByHeight: 5,
  flyBySwing: 20,
  orbitRadius: 9,
  orbitTilt: 15,
  scale: 1.0,
  speed: 1.0,
  spiralHeight: 5,
  spiralLoops: 2,
  trackingDistance: 6,
  trackingOffset: 1,
};

const MOTION_CONSTANTS = {
  EPSILON: 0.0001,
  MIN_DISTANCE: 0.5,
  DEFAULT_FOV: 50,
  PI2: Math.PI * 2,
  SPIRAL_CENTER: 0.5,
  FOV_MIN: 10,
  FOV_MAX: 120,
  MS_PER_SECOND: 1000,
  DEG_TO_RAD_FACTOR: 180,
  BASE_RATE: 0.5,
} as const;

// Easing functions for smooth motion
function easeInOutCubic(t: number): number {
  return t < 0.5 ? 4 * t * t * t : 1 - (-2 * t + 2) ** 3 / 2;
}

export function calculateMotion(
  type: MotionType,
  progress: number,
  basePose: CameraPose,
  params: Partial<MotionParams> = {},
  trackingTarget?: Vec3
): MotionResult | null {
  const p = { ...DEFAULT_MOTION_PARAMS, ...params };

  switch (type) {
    case 'ORBIT':
      return calculateOrbit(progress, basePose, p);
    case 'FLY_BY':
      return calculateFlyBy(progress, basePose, p);
    case 'SPIRAL':
      return calculateSpiral(progress, basePose, p);
    case 'DOLLY_ZOOM':
      return calculateDollyZoom(progress, basePose, p);
    case 'ARC':
      return calculateArc(progress, basePose, p);
    case 'TRACKING':
      return calculateTracking(basePose, p, trackingTarget);
    default:
      return null;
  }
}

export function calculateOrbit(
  progress: number,
  base: CameraPose,
  params: MotionParams
): MotionResult {
  const angle = progress * MOTION_CONSTANTS.PI2;
  const radius = params.orbitRadius;
  const tiltRad = degToRad(params.orbitTilt);

  const x = Math.sin(angle) * radius * Math.cos(tiltRad);
  const z = Math.cos(angle) * radius * Math.cos(tiltRad);
  const y = Math.sin(tiltRad) * radius;

  return {
    position: {
      x: base.target.x + x,
      y: base.target.y + y,
      z: base.target.z + z,
    },
    target: base.target,
    fov: base.fov,
  };
}

export function calculateFlyBy(
  progress: number,
  base: CameraPose,
  params: MotionParams
): MotionResult {
  const swing = params.flyBySwing;
  const height = params.flyByHeight;

  // Apply easing for smooth acceleration/deceleration
  const easedProgress = easeInOutCubic(progress);

  // Calculate base distance from camera to target
  const dx = base.position.x - base.target.x;
  const dy = base.position.y - base.target.y;
  const dz = base.position.z - base.target.z;
  const baseDist = Math.sqrt(dx * dx + dy * dy + dz * dz);
  const zBase = Math.max(MOTION_CONSTANTS.MIN_DISTANCE, baseDist);

  // Create an arc motion path using sine curves
  // Camera moves in an arc: starts from one side, sweeps across, ends on other side
  const angle = (easedProgress - 0.5) * Math.PI; // -π/2 to π/2
  const sinAngle = Math.sin(angle);
  const cosAngle = Math.cos(angle);

  // X position: arc trajectory with entry and exit
  const x = base.target.x + sinAngle * swing;

  // Z position: depth varies to create "approach and leave" feeling
  // Camera comes closer at middle of motion, starts/ends further away
  const zDepthVariation = cosAngle * (swing * 0.3);
  const z = base.target.z + zBase + zDepthVariation;

  // Y position: height with slight arc for natural flight path
  // Add slight rise in middle of motion
  const heightArc = Math.sin(easedProgress * Math.PI) * (height * 0.2);
  const y = base.target.y + height + heightArc;

  // Dynamic target point for "sweeping past" effect
  // Target moves slightly ahead of camera to create parallax
  const targetLead = sinAngle * swing * 0.4;
  const targetX = base.target.x + targetLead;

  // Add slight FOV variation for dramatic effect (zoom in when closest)
  const fovVariation = cosAngle * 2; // ±2 degrees
  const finalFov = Math.max(
    MOTION_CONSTANTS.FOV_MIN,
    Math.min(MOTION_CONSTANTS.FOV_MAX, base.fov + fovVariation)
  );

  return {
    position: { x, y, z },
    target: {
      x: targetX,
      y: base.target.y,
      z: base.target.z,
    },
    fov: finalFov,
  };
}

export function calculateSpiral(
  progress: number,
  base: CameraPose,
  params: MotionParams
): MotionResult {
  const loops = params.spiralLoops;
  const heightTotal = params.spiralHeight;
  const angle = progress * MOTION_CONSTANTS.PI2 * loops;
  const height = (progress - MOTION_CONSTANTS.SPIRAL_CENTER) * heightTotal;
  const radius = params.orbitRadius;

  return {
    position: {
      x: base.target.x + Math.sin(angle) * radius,
      y: base.target.y + height,
      z: base.target.z + Math.cos(angle) * radius,
    },
    target: base.target,
    fov: base.fov,
  };
}

export function calculateDollyZoom(
  progress: number,
  base: CameraPose,
  params: MotionParams
): MotionResult {
  const t = Math.sin(progress * MOTION_CONSTANTS.PI2);
  const range = params.dollyRange;
  const intensity = params.dollyIntensity;
  const distOffset = t * range;

  const dx = base.position.x - base.target.x;
  const dy = base.position.y - base.target.y;
  const dz = base.position.z - base.target.z;
  const baseDist = Math.sqrt(dx * dx + dy * dy + dz * dz);

  if (baseDist < MOTION_CONSTANTS.EPSILON) {
    return { position: base.position, target: base.target, fov: base.fov };
  }

  const dir = { x: dx / baseDist, y: dy / baseDist, z: dz / baseDist };
  const newDist = Math.max(MOTION_CONSTANTS.MIN_DISTANCE, baseDist + distOffset * intensity);

  const halfFovRad = degToRad(base.fov) / 2;
  const k = Math.tan(halfFovRad) * baseDist;
  const newHalfFov = Math.atan(k / newDist);
  const newFov = radToDeg(newHalfFov * 2);
  const finalFov = lerp(base.fov, newFov, intensity);

  return {
    position: {
      x: base.target.x + dir.x * newDist,
      y: base.target.y + dir.y * newDist,
      z: base.target.z + dir.z * newDist,
    },
    target: base.target,
    fov: Math.max(MOTION_CONSTANTS.FOV_MIN, Math.min(MOTION_CONSTANTS.FOV_MAX, finalFov)),
  };
}

export function calculateArc(
  progress: number,
  base: CameraPose,
  params: MotionParams
): MotionResult {
  const t = Math.sin(progress * MOTION_CONSTANTS.PI2);
  const maxAngle = degToRad(params.arcAngle);
  const angle = t * maxAngle;
  const radius = params.orbitRadius;

  const heightOffset = base.position.y - base.target.y;

  return {
    position: {
      x: base.target.x + Math.sin(angle) * radius,
      y: base.target.y + heightOffset,
      z: base.target.z + Math.cos(angle) * radius,
    },
    target: base.target,
    fov: base.fov,
  };
}

export function calculateTracking(
  base: CameraPose,
  params: MotionParams,
  trackingTarget?: Vec3
): MotionResult {
  if (!trackingTarget) {
    return { position: base.position, target: base.target, fov: base.fov };
  }

  const dist = params.trackingDistance;
  const offsetY = params.trackingOffset;

  return {
    position: {
      x: trackingTarget.x,
      y: trackingTarget.y + offsetY,
      z: trackingTarget.z + dist,
    },
    target: trackingTarget,
    fov: base.fov,
  };
}

export function calculateProgress(time: number, startTime: number, speed: number): number {
  const elapsed = (time - startTime) / MOTION_CONSTANTS.MS_PER_SECOND;

  return (elapsed * speed * MOTION_CONSTANTS.BASE_RATE) % 1;
}

function degToRad(deg: number): number {
  return (deg * Math.PI) / MOTION_CONSTANTS.DEG_TO_RAD_FACTOR;
}

function radToDeg(rad: number): number {
  return (rad * MOTION_CONSTANTS.DEG_TO_RAD_FACTOR) / Math.PI;
}

function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * t;
}

