export type { SceneTabProps };

import { createLogger } from '@/core/Logger';

import type { BrushStroke, ToolSettings, ToolType } from './types';

/** 最大图像尺寸限制，防止内存溢出 */
const MAX_IMAGE_SIZE = 4096;

/** 队列项类型 */
type QueueItem = [number, number];

export class DepthEditorEngine {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private depthData: ImageData;
  private history: BrushStroke[] = [];
  private historyIndex = -1;
  private logger = createLogger({ module: 'DepthEditorEngine' });
  private maxHistory = 50;
  private width = 0;
  private height = 0;

  constructor(canvas: HTMLCanvasElement, initialDepthData: ImageData) {
    // 检查图像尺寸
    if (initialDepthData.width > MAX_IMAGE_SIZE || initialDepthData.height > MAX_IMAGE_SIZE) {
      throw new Error(
        `Image size exceeds maximum allowed (${MAX_IMAGE_SIZE}x${MAX_IMAGE_SIZE}). Received: ${initialDepthData.width}x${initialDepthData.height}`
      );
    }

    this.canvas = canvas;
    const context = canvas.getContext('2d', { willReadFrequently: true });

    if (!context) throw new Error('Cannot get 2D context');
    this.ctx = context;
    this.width = initialDepthData.width;
    this.height = initialDepthData.height;
    this.depthData = initialDepthData;
    this.canvas.width = this.width;
    this.canvas.height = this.height;
    this.ctx.putImageData(initialDepthData, 0, 0);
    this.logger.info('DepthEditorEngine initialized', {
      width: this.width,
      height: this.height,
    });
  }

  addToHistory(stroke: BrushStroke): void {
    this.history = this.history.slice(0, this.historyIndex + 1);
    this.history.push(stroke);
    if (this.history.length > this.maxHistory) {
      this.history.shift();
    } else {
      this.historyIndex++;
    }
  }

  private applyBlur(x: number, y: number, settings: ToolSettings): void {
    const { size } = settings;
    const radius = Math.floor(size / 2);
    const imageData = this.ctx.getImageData(
      Math.max(0, x - radius),
      Math.max(0, y - radius),
      Math.min(size, this.width - (x - radius)),
      Math.min(size, this.height - (y - radius))
    );
    const { data } = imageData;
    const kernel = 3;
    const output = new Uint8ClampedArray(data);

    for (let py = kernel; py < imageData.height - kernel; py++) {
      for (let px = kernel; px < imageData.width - kernel; px++) {
        let sum = 0;
        let count = 0;

        for (let ky = -kernel; ky <= kernel; ky++) {
          for (let kx = -kernel; kx <= kernel; kx++) {
            const idx = ((py + ky) * imageData.width + (px + kx)) * 4;

            sum += data[idx] ?? 0;
            count++;
          }
        }
        const idx = (py * imageData.width + px) * 4;
        const avg = sum / count;

        output[idx] = avg;
        output[idx + 1] = avg;
        output[idx + 2] = avg;
      }
    }

    for (let i = 0; i < output.length; i++) {
      data[i] = output[i] ?? 0;
    }

    this.ctx.putImageData(imageData, Math.max(0, x - radius), Math.max(0, y - radius));
  }

  private applyFill(x: number, y: number, settings: ToolSettings): void {
    const { depthValue } = settings;
    const imageData = this.ctx.getImageData(0, 0, this.width, this.height);
    const { data } = imageData;
    const px = Math.floor(x);
    const py = Math.floor(y);

    if (!this.isValidPixel(px, py)) return;

    const idx = (py * this.width + px) * 4;
    const targetDepth = data[idx] ?? 0;

    if (Math.abs(targetDepth - depthValue) < 1) return;

    this.floodFill(data, px, py, targetDepth, depthValue);
    this.ctx.putImageData(imageData, 0, 0);
  }

  private applySharpen(x: number, y: number, settings: ToolSettings): void {
    const { size } = settings;
    const radius = Math.floor(size / 2);
    const imageData = this.ctx.getImageData(
      Math.max(0, x - radius),
      Math.max(0, y - radius),
      Math.min(size, this.width - (x - radius)),
      Math.min(size, this.height - (y - radius))
    );
    const { data } = imageData;
    const output = new Uint8ClampedArray(data);

    const kernel = [
      [0, -1, 0],
      [-1, 5, -1],
      [0, -1, 0],
    ];

    for (let py = 1; py < imageData.height - 1; py++) {
      for (let px = 1; px < imageData.width - 1; px++) {
        let sum = 0;

        for (let ky = -1; ky <= 1; ky++) {
          for (let kx = -1; kx <= 1; kx++) {
            const idx = ((py + ky) * imageData.width + (px + kx)) * 4;

            sum += (data[idx] ?? 0) * (kernel[ky + 1]?.[kx + 1] ?? 0);
          }
        }
        const idx = (py * imageData.width + px) * 4;

        output[idx] = Math.min(255, Math.max(0, sum));
        output[idx + 1] = output[idx];
        output[idx + 2] = output[idx];
      }
    }

    for (let i = 0; i < output.length; i++) {
      data[i] = output[i] ?? 0;
    }

    this.ctx.putImageData(imageData, Math.max(0, x - radius), Math.max(0, y - radius));
  }

  applyTool(tool: ToolType, x: number, y: number, settings: ToolSettings, pressure = 1.0): void {
    switch (tool) {
      case 'brush':
        this.drawBrush(x, y, settings, pressure);
        break;
      case 'eraser':
        this.drawEraser(x, y, settings, pressure);
        break;
      case 'blur':
        this.applyBlur(x, y, settings);
        break;
      case 'sharpen':
        this.applySharpen(x, y, settings);
        break;
      case 'fill':
        this.applyFill(x, y, settings);
        break;
      case 'eyedropper':
        break;
    }
  }

  dispose(): void {
    this.history = [];
    this.historyIndex = -1;
    this.logger.info('DepthEditorEngine disposed');
  }

  private drawBrush(x: number, y: number, settings: ToolSettings, pressure: number): void {
    const { size, opacity, hardness, depthValue } = settings;
    const radius = Math.floor(size / 2) * pressure;
    const imageData = this.ctx.getImageData(0, 0, this.width, this.height);
    const { data } = imageData;

    for (let dy = -radius; dy <= radius; dy++) {
      for (let dx = -radius; dx <= radius; dx++) {
        const distance = Math.sqrt(dx * dx + dy * dy);

        if (distance > radius) continue;

        const px = Math.floor(x + dx);
        const py = Math.floor(y + dy);

        if (px < 0 || px >= this.width || py < 0 || py >= this.height) continue;

        const idx = (py * this.width + px) * 4;
        const falloff = (1 - distance / radius) ** (hardness * 2);
        const alpha = opacity * falloff * pressure;

        const currentDepth = data[idx] ?? 0;
        const newDepth = currentDepth * (1 - alpha) + depthValue * alpha;

        data[idx] = newDepth;
        data[idx + 1] = newDepth;
        data[idx + 2] = newDepth;
        data[idx + 3] = 255;
      }
    }

    this.ctx.putImageData(imageData, 0, 0);
  }

  private drawEraser(x: number, y: number, settings: ToolSettings, pressure: number): void {
    const { size, opacity } = settings;
    const radius = Math.floor(size / 2) * pressure;
    const imageData = this.ctx.getImageData(0, 0, this.width, this.height);
    const { data } = imageData;
    const originalData = this.depthData.data;

    for (let dy = -radius; dy <= radius; dy++) {
      for (let dx = -radius; dx <= radius; dx++) {
        const distance = Math.sqrt(dx * dx + dy * dy);

        if (distance > radius) continue;

        const px = Math.floor(x + dx);
        const py = Math.floor(y + dy);

        if (px < 0 || px >= this.width || py < 0 || py >= this.height) continue;

        const idx = (py * this.width + px) * 4;
        const alpha = opacity * pressure * (1 - distance / radius);

        const currentDepth = data[idx] ?? 0;
        const originalDepth = originalData[idx] ?? 0;
        const newDepth = currentDepth * (1 - alpha) + originalDepth * alpha;

        data[idx] = newDepth;
        data[idx + 1] = newDepth;
        data[idx + 2] = newDepth;
      }
    }

    this.ctx.putImageData(imageData, 0, 0);
  }

  /**
   * 使用广度优先搜索 (BFS) 实现 floodFill
   * 相比深度优先搜索，BFS 使用队列实现，可以避免递归栈溢出
   */
  private floodFill(
    data: Uint8ClampedArray,
    startX: number,
    startY: number,
    targetDepth: number,
    depthValue: number
  ): void {
    // 使用队列实现 BFS，避免栈溢出
    const queue: QueueItem[] = [[startX, startY]];
    // 使用 Uint8Array 替代 Set<string>，内存效率更高
    const visited = new Uint8Array(this.width * this.height);
    const width = this.width;

    while (queue.length > 0) {
      const [cx, cy] = queue.shift()!;
      const idx = cy * width + cx;

      if (visited[idx]) continue;
      visited[idx] = 1;

      if (!this.isValidPixel(cx, cy)) continue;

      const cidx = idx * 4;
      const currentDepth = data[cidx] ?? 0;

      if (Math.abs(currentDepth - targetDepth) <= 10) {
        this.setPixelDepth(data, cidx, depthValue);

        // 添加邻居到队列（带边界检查）
        const left = cx - 1;
        const right = cx + 1;
        const up = cy - 1;
        const down = cy + 1;

        if (left >= 0 && !visited[idx - 1]) queue.push([left, cy]);
        if (right < width && !visited[idx + 1]) queue.push([right, cy]);
        if (up >= 0 && !visited[idx - width]) queue.push([cx, up]);
        if (down < this.height && !visited[idx + width]) queue.push([cx, down]);
      }
    }
  }

  getDepthData(): ImageData {
    return this.ctx.getImageData(0, 0, this.width, this.height);
  }

  getDepthValue(x: number, y: number): number {
    const px = Math.floor(x);
    const py = Math.floor(y);

    if (px < 0 || px >= this.width || py < 0 || py >= this.height) return 128;

    const imageData = this.ctx.getImageData(px, py, 1, 1);

    return imageData.data[0] ?? 128;
  }

  private isValidPixel(x: number, y: number): boolean {
    return x >= 0 && x < this.width && y >= 0 && y < this.height;
  }

  redo(): boolean {
    if (this.historyIndex >= this.history.length - 1) return false;
    this.historyIndex++;
    this.replayHistory();

    return true;
  }

  /**
   * 优化后的 replayHistory
   * 复用单个 ImageData 而不是多次调用 getImageData
   */
  private replayHistory(): void {
    // 复用深度数据，避免重复创建 ImageData
    const currentData = this.ctx.getImageData(0, 0, this.width, this.height);
    const { data } = currentData;
    const originalData = this.depthData.data;

    for (let i = 0; i <= this.historyIndex; i++) {
      const stroke = this.history[i];

      if (!stroke) continue;

      for (const point of stroke.points) {
        this.applyStrokeToData(data, originalData, stroke.tool, point.x, point.y, stroke.settings, point.pressure);
      }
    }

    this.ctx.putImageData(currentData, 0, 0);
  }

  /**
   * 直接操作 ImageData 的笔刷应用，比调用 applyTool 更高效
   */
  private applyStrokeToData(
    data: Uint8ClampedArray,
    originalData: Uint8ClampedArray,
    tool: ToolType,
    x: number,
    y: number,
    settings: ToolSettings,
    pressure: number
  ): void {
    const { size, opacity, hardness, depthValue } = settings;
    const radius = Math.floor(size / 2) * pressure;

    for (let dy = -radius; dy <= radius; dy++) {
      for (let dx = -radius; dx <= radius; dx++) {
        const distance = Math.sqrt(dx * dx + dy * dy);

        if (distance > radius) continue;

        const px = Math.floor(x + dx);
        const py = Math.floor(y + dy);

        if (px < 0 || px >= this.width || py < 0 || py >= this.height) continue;

        const idx = (py * this.width + px) * 4;

        if (tool === 'brush') {
          const falloff = (1 - distance / radius) ** (hardness * 2);
          const alpha = opacity * falloff * pressure;
          const currentDepth = data[idx] ?? 0;
          const newDepth = currentDepth * (1 - alpha) + depthValue * alpha;

          data[idx] = newDepth;
          data[idx + 1] = newDepth;
          data[idx + 2] = newDepth;
          data[idx + 3] = 255;
        } else if (tool === 'eraser') {
          const alpha = opacity * pressure * (1 - distance / radius);
          const currentDepth = data[idx] ?? 0;
          const originalDepth = originalData[idx] ?? 0;
          const newDepth = currentDepth * (1 - alpha) + originalDepth * alpha;

          data[idx] = newDepth;
          data[idx + 1] = newDepth;
          data[idx + 2] = newDepth;
        }
      }
    }
  }

  reset(): void {
    this.ctx.putImageData(this.depthData, 0, 0);
    this.history = [];
    this.historyIndex = -1;
  }

  private setPixelDepth(data: Uint8ClampedArray, idx: number, depthValue: number): void {
    data[idx] = depthValue;
    data[idx + 1] = depthValue;
    data[idx + 2] = depthValue;
    data[idx + 3] = 255;
  }

  undo(): boolean {
    if (this.historyIndex < 0) return false;
    this.historyIndex--;
    this.replayHistory();

    return true;
  }
}

import { useFrame } from '@react-three/fiber';
import { memo, useMemo, useRef } from 'react';
import type { Points } from 'three';
import { AdditiveBlending, BufferAttribute, BufferGeometry, CanvasTexture, Color, PointsMaterial } from 'three';
import { ANIMATION, PARTICLE, PARTICLE_COLORS, STAR, STAR_COUNT } from './constants';

export type ParticleType = 'dust' | 'snow' | 'stars' | 'firefly' | 'rain' | 'leaves';

interface AtmosphereParticlesProps {
  enabled?: boolean;
  particleType?: ParticleType;
  density?: number;
  color?: string;
  speedFactor?: number;
}

interface ParticleData {
  colors: Float32Array;
  geometry: BufferGeometry;
  phases: Float32Array;
  positions: Float32Array;
  scales: Float32Array; // Renamed from sizes to avoid conflict with PointsMaterial size
  velocities: Float32Array;
}

const createParticleData = (
  count: number,
  type: ParticleType,
  density: number,
  overrideColor?: string
): ParticleData => {
  const finalCount = Math.floor(count * density);
  const positions = new Float32Array(finalCount * ANIMATION.BUFFER_STRIDE_3);
  const velocities = new Float32Array(finalCount * ANIMATION.BUFFER_STRIDE_3);
  const colors = new Float32Array(finalCount * ANIMATION.BUFFER_STRIDE_3);
  const scales = new Float32Array(finalCount);
  const phases = new Float32Array(finalCount);
  const geometry = new BufferGeometry();

  const spread =
    type === 'stars' ? PARTICLE.SPREAD * PARTICLE.STARS_SPREAD_MULTIPLIER : PARTICLE.SPREAD;

  for (let i = 0; i < finalCount; i++) {
    const i3 = i * ANIMATION.BUFFER_STRIDE_3;

    positions[i3] = (Math.random() - ANIMATION.HALF) * spread;
    positions[i3 + 1] = (Math.random() - ANIMATION.HALF) * spread;
    positions[i3 + 2] = (Math.random() - ANIMATION.HALF) * spread;

    phases[i] = Math.random() * Math.PI * ANIMATION.PHASE_TWO_PI;

    initializeParticle(type, i, i3, velocities, colors, scales, overrideColor);
  }

  geometry.setAttribute('position', new BufferAttribute(positions, ANIMATION.BUFFER_STRIDE_3));
  geometry.setAttribute('color', new BufferAttribute(colors, ANIMATION.BUFFER_STRIDE_3));
  geometry.setAttribute('scales', new BufferAttribute(scales, ANIMATION.BUFFER_STRIDE_1));

  return { geometry, positions, velocities, colors, scales, phases };
};

const initDust = (
  i3: number,
  index: number,
  velocities: Float32Array,
  colors: Float32Array,
  scales: Float32Array,
  overrideColor?: string
): void => {
  const color = new Color();

  velocities[i3] = (Math.random() - ANIMATION.HALF) * ANIMATION.DUST_BROWNIAN_STRENGTH;
  velocities[i3 + 1] = Math.random() * ANIMATION.DUST_BROWNIAN_STRENGTH;
  velocities[i3 + 2] = (Math.random() - ANIMATION.HALF) * ANIMATION.DUST_BROWNIAN_STRENGTH;

  if (overrideColor) {
    color.set(overrideColor);
  } else {
    color.set(
      Math.random() > ANIMATION.HALF ? PARTICLE_COLORS.DUST.BASE : PARTICLE_COLORS.DUST.VARIANT1
    );
  }
  colors[i3] = color.r;
  colors[i3 + 1] = color.g;
  colors[i3 + 2] = color.b;
  scales[index] = ANIMATION.DUST_SIZE_BASE + Math.random() * ANIMATION.DUST_SIZE_RANGE;
};

const initSnow = (
  i3: number,
  index: number,
  velocities: Float32Array,
  colors: Float32Array,
  scales: Float32Array
): void => {
  const color = new Color();

  velocities[i3] = (Math.random() - ANIMATION.HALF) * ANIMATION.SNOW_WIND_STRENGTH;
  velocities[i3 + 1] = -(ANIMATION.SNOW_FALL_BASE + Math.random() * ANIMATION.SNOW_FALL_RANGE);
  velocities[i3 + 2] = (Math.random() - ANIMATION.HALF) * ANIMATION.SNOW_WIND_STRENGTH;
  color.set(
    Math.random() > ANIMATION.SNOW_WHITE_THRESHOLD
      ? PARTICLE_COLORS.SNOW.BASE
      : PARTICLE_COLORS.SNOW.SHADOW
  );
  colors[i3] = color.r;
  colors[i3 + 1] = color.g;
  colors[i3 + 2] = color.b;
  scales[index] = ANIMATION.SNOW_SIZE_BASE + Math.random() * ANIMATION.SNOW_SIZE_VARIATION;
};

const initStars = (
  i3: number,
  index: number,
  velocities: Float32Array,
  colors: Float32Array,
  scales: Float32Array
): void => {
  const color = new Color();

  velocities[i3] = 0;
  velocities[i3 + 1] = 0;
  velocities[i3 + 2] = 0;
  const colorRand = Math.random();

  if (colorRand < ANIMATION.STAR_COLOR_BLUE_THRESHOLD) color.set(PARTICLE_COLORS.STAR.WHITE);
  else if (colorRand < ANIMATION.STAR_COLOR_WARM_THRESHOLD) color.set(PARTICLE_COLORS.STAR.BLUE);
  else color.set(PARTICLE_COLORS.STAR.WARM);
  colors[i3] = color.r;
  colors[i3 + 1] = color.g;
  colors[i3 + 2] = color.b;

  // Power-law distribution for sizes: Many small stars, few large ones
  // Math.pow(Math.random(), 4.0) produces more values near 0, creating accurate star field look
  scales[index] = STAR.SIZE_MIN + Math.pow(Math.random(), 4.0) * STAR.SIZE_RANGE * 1.5;
};

const initFirefly = (
  i3: number,
  index: number,
  velocities: Float32Array,
  colors: Float32Array,
  scales: Float32Array
): void => {
  const color = new Color();

  velocities[i3] = (Math.random() - ANIMATION.HALF) * ANIMATION.FIREFLY_DRIFT;
  velocities[i3 + 1] = (Math.random() - ANIMATION.HALF) * ANIMATION.FIREFLY_DRIFT;
  velocities[i3 + 2] = (Math.random() - ANIMATION.HALF) * ANIMATION.FIREFLY_DRIFT;
  color.set(
    Math.random() > ANIMATION.FIREFLY_CORE_THRESHOLD
      ? PARTICLE_COLORS.FIREFLY.GLOW
      : PARTICLE_COLORS.FIREFLY.TRAIL
  );
  colors[i3] = color.r;
  colors[i3 + 1] = color.g;
  colors[i3 + 2] = color.b;
  scales[index] = ANIMATION.FIREFLY_SIZE_BASE + Math.random() * ANIMATION.FIREFLY_SIZE_RANGE;
};

const initRain = (
  i3: number,
  index: number,
  velocities: Float32Array,
  colors: Float32Array,
  scales: Float32Array
): void => {
  const color = new Color();

  velocities[i3] = (Math.random() - ANIMATION.HALF) * ANIMATION.RAIN_WIND_STRENGTH;
  velocities[i3 + 1] = -(ANIMATION.RAIN_FALL_BASE + Math.random() * ANIMATION.RAIN_FALL_RANGE);
  velocities[i3 + 2] = (Math.random() - ANIMATION.HALF) * ANIMATION.RAIN_WIND_STRENGTH;
  color.set(
    Math.random() > ANIMATION.HALF ? PARTICLE_COLORS.RAIN.BASE : PARTICLE_COLORS.RAIN.LIGHT
  );
  colors[i3] = color.r;
  colors[i3 + 1] = color.g;
  colors[i3 + 2] = color.b;
  scales[index] = ANIMATION.RAIN_SIZE_BASE + Math.random() * ANIMATION.RAIN_SIZE_RANGE;
};

const initLeaves = (
  i3: number,
  index: number,
  velocities: Float32Array,
  colors: Float32Array,
  scales: Float32Array
): void => {
  const color = new Color();

  velocities[i3] = (Math.random() - ANIMATION.HALF) * ANIMATION.LEAVES_WIND_STRENGTH;
  velocities[i3 + 1] = -(ANIMATION.LEAVES_FALL_BASE + Math.random() * ANIMATION.LEAVES_FALL_RANGE);
  velocities[i3 + 2] = (Math.random() - ANIMATION.HALF) * ANIMATION.LEAVES_WIND_STRENGTH;
  const leafRand = Math.random();

  if (leafRand < ANIMATION.LEAVES_GREEN_THRESHOLD) color.set(PARTICLE_COLORS.LEAVES.GREEN);
  else if (leafRand < ANIMATION.LEAVES_YELLOW_THRESHOLD) color.set(PARTICLE_COLORS.LEAVES.YELLOW);
  else if (leafRand < ANIMATION.LEAVES_ORANGE_THRESHOLD) color.set(PARTICLE_COLORS.LEAVES.ORANGE);
  else color.set(PARTICLE_COLORS.LEAVES.RED);
  colors[i3] = color.r;
  colors[i3 + 1] = color.g;
  colors[i3 + 2] = color.b;
  scales[index] = ANIMATION.LEAVES_SIZE_BASE + Math.random() * ANIMATION.LEAVES_SIZE_RANGE;
};

const initializeParticle = (
  type: ParticleType,
  index: number,
  i3: number,
  velocities: Float32Array,
  colors: Float32Array,
  scales: Float32Array,
  overrideColor?: string
): void => {
  switch (type) {
    case 'dust':
      initDust(i3, index, velocities, colors, scales, overrideColor);
      break;
    case 'snow':
      initSnow(i3, index, velocities, colors, scales);
      break;
    case 'stars':
      initStars(i3, index, velocities, colors, scales);
      break;
    case 'firefly':
      initFirefly(i3, index, velocities, colors, scales);
      break;
    case 'rain':
      initRain(i3, index, velocities, colors, scales);
      break;
    case 'leaves':
      initLeaves(i3, index, velocities, colors, scales);
      break;
  }
};

const updateParticles = (
  data: ParticleData,
  count: number,
  time: number,
  spread: number,
  type: ParticleType
): void => {
  const { positions, velocities, phases, scales } = data;
  const halfSpread = spread / ANIMATION.PHASE_TWO_PI;

  for (let i = 0; i < count; i++) {
    const i3 = i * ANIMATION.BUFFER_STRIDE_3;
    const phase = phases[i] ?? 0;

    let posX = positions[i3] ?? 0;
    let posY = positions[i3 + 1] ?? 0;
    let posZ = positions[i3 + 2] ?? 0;
    const velX = velocities[i3] ?? 0;
    const velY = velocities[i3 + 1] ?? 0;
    const velZ = velocities[i3 + 2] ?? 0;

    updateParticleByType(
      type,
      time,
      phase,
      velX,
      velY,
      velZ,
      scales,
      i,
      { posX, posY, posZ },
      (p) => {
        ({ posX, posY, posZ } = p);
      }
    );

    posX = wrapPosition(posX, halfSpread);
    posZ = wrapPosition(posZ, halfSpread);
    if (posY < -halfSpread) {
      posY = halfSpread;
      posX = (Math.random() - ANIMATION.HALF) * spread;
      posZ = (Math.random() - ANIMATION.HALF) * spread;
    }
    if (posY > halfSpread) posY = -halfSpread;

    positions[i3] = posX;
    positions[i3 + 1] = posY;
    positions[i3 + 2] = posZ;
  }
};

const wrapPosition = (pos: number, half: number): number => {
  if (pos > half) return -half;
  if (pos < -half) return half;

  return pos;
};

const updateParticleByType = (
  type: ParticleType,
  time: number,
  phase: number,
  velX: number,
  velY: number,
  velZ: number,
  scales: Float32Array,
  i: number,
  pos: { posX: number; posY: number; posZ: number },
  setPos: (p: { posX: number; posY: number; posZ: number }) => void
): void => {
  let { posX, posY, posZ } = pos;

  switch (type) {
    case 'dust':
      posX += velX + Math.sin(time + phase) * ANIMATION.DUST_BROWNIAN_STRENGTH;
      posY +=
        velY +
        Math.cos(time * ANIMATION.DUST_TIME_FACTOR_Y + phase) * ANIMATION.DUST_BROWNIAN_STRENGTH;
      posZ +=
        velZ +
        Math.sin(time * ANIMATION.DUST_TIME_FACTOR_Z + phase) * ANIMATION.DUST_BROWNIAN_STRENGTH;

      // Simple Dust Twinkle
      {
         const baseSize = ANIMATION.DUST_SIZE_BASE + (phase / (Math.PI * ANIMATION.PHASE_TWO_PI)) * ANIMATION.DUST_SIZE_RANGE;
         const twinkle = 0.8 + 0.3 * Math.sin(time * 2.0 + phase) + 0.2 * Math.cos(time * 5.0 + phase * 2.0);

         scales[i] = baseSize * twinkle;
      }
      break;
    case 'snow':
      posX += velX + Math.sin(time * ANIMATION.DUST_TIME_FACTOR_Z + phase) * ANIMATION.SNOW_DRIFT;
      posY += velY;
      posZ +=
        velZ +
        Math.cos(time * ANIMATION.FIREFLY_PULSE_MIN + phase) *
          ANIMATION.SNOW_DRIFT *
          ANIMATION.HALF;
      break;
    case 'stars':
      {
        // Irregular Twinkle: Three sine waves with prime number frequencies + random phase
        const twinkle =
          0.7 + // Base brightness
          0.3 * Math.sin(time * 3.0 + phase) + // Slow breathe
          0.3 * Math.sin(time * 7.0 + phase * 2.0) + // Medium pulse
          0.1 * Math.sin(time * 13.0 + phase * 3.0); // Fast flutter

        // Re-calculate base size to avoid drift (deterministic from phase)
        const baseSizeProjection = Math.pow((phase / (Math.PI * ANIMATION.PHASE_TWO_PI)), 4.0);
        const baseSize = STAR.SIZE_MIN + baseSizeProjection * STAR.SIZE_RANGE * 1.5;

        scales[i] = baseSize * Math.max(0.2, twinkle); // Ensure it doesn't invert
      }
      break;
    case 'firefly':
      {
        const isPaused =
          Math.sin(
            time * ANIMATION.FIREFLY_PULSE_MIN + phase * ANIMATION.FIREFLY_PAUSE_PHASE_MULT
          ) > ANIMATION.SNOW_WHITE_THRESHOLD;

        if (!isPaused) {
          posX += velX;
          posY +=
            velY +
            Math.sin(time * ANIMATION.FIREFLY_TIME_MULTIPLIER + phase) *
              ANIMATION.FIREFLY_VERTICAL_WAVE;
          posZ += velZ;
        }
        const pulse =
          ANIMATION.FIREFLY_PULSE_MIN +
          ANIMATION.SNOW_WHITE_THRESHOLD *
            (ANIMATION.HALF +
              ANIMATION.HALF * Math.sin(time * ANIMATION.FIREFLY_PULSE_SPEED + phase));

        scales[i] =
          (ANIMATION.FIREFLY_SIZE_BASE + Math.random() * ANIMATION.FIREFLY_SIZE_JITTER) * pulse;
      }
      break;
    case 'rain':
      posX +=
        velX + Math.sin(time * ANIMATION.RAIN_WAVE_SPEED + phase) * ANIMATION.RAIN_WAVE_STRENGTH;
      posY += velY;
      posZ += velZ;
      break;
    case 'leaves':
      posX +=
        velX + Math.sin(time * ANIMATION.LEAVES_SWAY_SPEED_X + phase) * ANIMATION.LEAVES_SWAY_X;
      posY +=
        velY +
        Math.sin(time * ANIMATION.LEAVES_SWAY_SPEED_Y + phase * ANIMATION.PHASE_TWO_PI) *
          ANIMATION.LEAVES_SWAY_Y;
      posZ +=
        velZ + Math.cos(time * ANIMATION.LEAVES_SWAY_SPEED_Z + phase) * ANIMATION.LEAVES_SWAY_Z;
      break;
  }
  setPos({ posX, posY, posZ });
};

// --- Soft Particle Texture Generation ---
const getSoftParticleTexture = (() => {
  let texture: CanvasTexture | null = null;

  return () => {
    if (texture) return texture;
    const canvas = document.createElement('canvas');

    canvas.width = 32;
    canvas.height = 32;
    const ctx = canvas.getContext('2d');

    if (ctx) {
      const gradient = ctx.createRadialGradient(16, 16, 0, 16, 16, 16);

      gradient.addColorStop(0, 'rgba(255, 255, 255, 1)');
      gradient.addColorStop(1, 'rgba(255, 255, 255, 0)');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, 32, 32);
    }
    texture = new CanvasTexture(canvas);

    return texture;
  };
})();

const RAIN_COUNT = 2500; // Increased base count allowing density scaling
const MATERIAL_SIZE_RAIN = 0.08;
const MATERIAL_SIZE_DEFAULT = 0.3; // Slightly larger for soft texture
const MATERIAL_OPACITY_RAIN = 0.8;
const MATERIAL_OPACITY_DEFAULT = 0.9;

const AtmosphereParticlesComponent = ({
  enabled = true,
  particleType = 'dust',
  density = 1.0,
  color,
  speedFactor = 0.5,
}: AtmosphereParticlesProps) => {
  const pointsRef = useRef<Points>(null);
  const count = particleType === 'rain' ? RAIN_COUNT : (particleType === 'stars' ? STAR_COUNT : PARTICLE.COUNT);
  const spread =
    particleType === 'stars' ? PARTICLE.SPREAD * PARTICLE.STARS_SPREAD_MULTIPLIER : PARTICLE.SPREAD;

  const particleData = useMemo(
    () => createParticleData(count, particleType, density, color),
    [count, particleType, density, color]
  );

  const material = useMemo(() => {
    const m = new PointsMaterial({
      size: (particleType === 'rain' ? MATERIAL_SIZE_RAIN : MATERIAL_SIZE_DEFAULT) * (1 + (speedFactor - 0.5) * 0.5),
      vertexColors: true,
      transparent: true,
      opacity: particleType === 'rain' ? MATERIAL_OPACITY_RAIN : MATERIAL_OPACITY_DEFAULT,
      blending: AdditiveBlending,
      depthWrite: false,
      sizeAttenuation: true,
      map: getSoftParticleTexture(),
      alphaTest: 0.01,
    });

    // Custom Shader Injection for per-vertex scaling
    /* TEMPORARILY DISABLED FOR DEBUGGING
    m.onBeforeCompile = (shader) => {
      // Must manually declare custom attributes for PointsMaterial
      shader.vertexShader = `
        attribute float scales;
        ${shader.vertexShader}
      `;

      // Debug: Log original shader to match string
      // console.log('Original Vertex Shader:', shader.vertexShader);

      // Inject scale multiplication into point size calculation
      const originalPointSize = 'gl_PointSize = size;';
      const replacementPointSize = 'gl_PointSize = size * scales;';

      if (shader.vertexShader.includes(originalPointSize)) {
         shader.vertexShader = shader.vertexShader.replace(originalPointSize, replacementPointSize);
      } else {
         console.warn('AtmosphereParticles: Failed to inject scales into simple point size assignment');
      }

      const originalAttenuation = 'gl_PointSize = size * ( scale / - mvPosition.z );';
      const replacementAttenuation = 'gl_PointSize = size * scales * ( scale / - mvPosition.z );';

      if (shader.vertexShader.includes(originalAttenuation)) {
          shader.vertexShader = shader.vertexShader.replace(originalAttenuation, replacementAttenuation);
      } else {
          // This is expected if the simple replacement worked and attenuation is handled separately,
          // OR if the string format is different.
          // Let's print a part of shader to verify.
          // console.log('Shader check:', shader.vertexShader.substring(shader.vertexShader.indexOf('void main'), shader.vertexShader.length));
      }
    };
    */
    return m;
  }, [particleType, speedFactor]);

  useFrame(({ clock }) => {
    if (!enabled || !pointsRef.current) return;

    // Use speedFactor to modulate time/speed
    // e.g., speedFactor 0.5 is 1x speed. 1.0 is 2x speed.
    const dynamicSpeed = 0.5 + speedFactor;
    const time = clock.getElapsedTime() * dynamicSpeed;

    // We pass the actual count of particles created (which is scaled by density)
    // createParticleData returns arrays sized by finalCount, so we should allow updateParticles
    // to iterate up to the length of the arrays it created.
    updateParticles(particleData, particleData.phases.length, time, spread, particleType);

    const positionAttr = particleData.geometry.getAttribute('position');
    const scaleAttr = particleData.geometry.getAttribute('scales');

    if (positionAttr) positionAttr.needsUpdate = true;
    if (scaleAttr) scaleAttr.needsUpdate = true;
  });

  if (!enabled) return null;

  return <points geometry={particleData.geometry} material={material} ref={pointsRef} />;
};

export const AtmosphereParticles = memo(AtmosphereParticlesComponent);

AtmosphereParticles.displayName = 'AtmosphereParticles';

import { getEventBus } from '@/core/EventBus';
import { Html } from '@react-three/drei';
import { memo, useEffect, useState } from 'react';
import type { Vector3 } from 'three';
import {
  getMeasurementService,
  type Measurement,
} from '../../services/measurement/MeasurementService';

interface MeasurementOverlayProps {
  visible?: boolean;
}

const MeasurementOverlayComponent: React.FC<MeasurementOverlayProps> = ({ visible = true }) => {
  const [measurements, setMeasurements] = useState<Measurement[]>([]);
  const [currentPoints, setCurrentPoints] = useState<Vector3[]>([]);

  // 订阅测量变化
  useEffect(() => {
    const service = getMeasurementService();
    const eventBus = getEventBus();

    const handleCompleted = (payload: unknown) => {
      const { measurement } = payload as { measurement: Measurement };

      setMeasurements((prev) => [...prev, measurement]);

      setCurrentPoints([]);
    };

    const handleCleared = () => {
      setMeasurements([]);

      setCurrentPoints([]);
    };

    const handlePointAdded = () => {
      setCurrentPoints(service.getCurrentPoints());
    };

    const handleDeleted = (payload: unknown) => {
      const { id } = payload as { id: string };

      setMeasurements((prev) => prev.filter((m) => m.id !== id));
    };

    // 使用事件监听
    eventBus.on('measurement:completed', handleCompleted);
    eventBus.on('measurement:cleared', handleCleared);
    eventBus.on('measurement:point-added', handlePointAdded);
    eventBus.on('measurement:deleted', handleDeleted);

    // 初始化当前测量
    setMeasurements(service.getMeasurements());
    setCurrentPoints(service.getCurrentPoints());

    return () => {
      eventBus.off('measurement:completed', handleCompleted);
      eventBus.off('measurement:cleared', handleCleared);
      eventBus.off('measurement:point-added', handlePointAdded);
      eventBus.off('measurement:deleted', handleDeleted);
    };
  }, []);

  if (!visible) return null;

  return (
    <group name="MeasurementOverlay">
      {/* 完成的测量 */}
      {measurements.map((measurement) => (
        <MeasurementItem key={measurement.id} measurement={measurement} />
      ))}

      {/* 当前正在进行的测量 */}
      {currentPoints.length > 0 && <CurrentMeasurementPoints points={currentPoints} />}
    </group>
  );
};

// 单个测量项组件
const MeasurementItem: React.FC<{ measurement: Measurement }> = memo(({ measurement }) => {
  if (measurement.type === 'distance') {
    const p1 = measurement.points[0]!;
    const p2 = measurement.points[1]!;

    // 计算中点用于显示标签
    const midpoint = p1.clone().add(p2).multiplyScalar(0.5);

    return (
      <group>
        {/* 连接线 */}
        <line>
          <bufferGeometry>
            <bufferAttribute
              attach="attributes-position"
              count={2}
              args={[new Float32Array([...p1.toArray(), ...p2.toArray()]), 3]}
            />
          </bufferGeometry>
          <lineBasicMaterial color="#00ff88" linewidth={2} />
        </line>

        {/* 端点标记 */}
        <mesh position={p1}>
          <sphereGeometry args={[0.1, 16, 16]} />
          <meshBasicMaterial color="#00ff88" />
        </mesh>
        <mesh position={p2}>
          <sphereGeometry args={[0.1, 16, 16]} />
          <meshBasicMaterial color="#00ff88" />
        </mesh>

        {/* 标签 */}
        <Html position={[midpoint.x, midpoint.y + 0.5, midpoint.z]} center>
          <div className="px-2 py-1 bg-black/80 text-green-400 text-xs rounded border border-green-500/50 whitespace-nowrap">
            {measurement.label}
          </div>
        </Html>
      </group>
    );
  }

  if (measurement.type === 'angle' && measurement.points.length === 3) {
    const p1 = measurement.points[0]!;
    const p2 = measurement.points[1]!;
    const p3 = measurement.points[2]!;

    return (
      <group>
        {/* 连接线 */}
        <line>
          <bufferGeometry>
            <bufferAttribute
              attach="attributes-position"
              count={3}
              args={[new Float32Array([...p1!.toArray(), ...p2!.toArray(), ...p3!.toArray()]), 3]}
            />
          </bufferGeometry>
          <lineBasicMaterial color="#ff8800" linewidth={2} />
        </line>

        {/* 端点标记 */}
        {measurement.points.map((point) => (
          <mesh key={`${point.x}-${point.y}-${point.z}`} position={point}>
            <sphereGeometry args={[0.1, 16, 16]} />
            <meshBasicMaterial color="#ff8800" />
          </mesh>
        ))}

        {/* 角度标签 */}
        <Html position={measurement.points[1]!.toArray()} center>
          <div className="px-2 py-1 bg-black/80 text-orange-400 text-xs rounded border border-orange-500/50 whitespace-nowrap">
            {measurement.label}
          </div>
        </Html>
      </group>
    );
  }

  return null;
});

// 当前测量点组件
const CurrentMeasurementPoints: React.FC<{ points: Vector3[] }> = memo(({ points }) => {
  return (
    <group>
      {/* 连接线 */}
      {points.length === 2 && (
        <line>
          <bufferGeometry>
            <bufferAttribute
              attach="attributes-position"
              count={2}
              args={[new Float32Array([...points[0]!.toArray(), ...points[1]!.toArray()]), 3]}
            />
          </bufferGeometry>
          <lineBasicMaterial color="#00aaff" linewidth={2} transparent opacity={0.7} />
        </line>
      )}

      {/* 点标记 */}
      {points.map((point) => (
        <mesh key={`${point.x}-${point.y}-${point.z}`} position={point}>
          <sphereGeometry args={[0.08, 16, 16]} />
          <meshBasicMaterial color="#00aaff" />
        </mesh>
      ))}
    </group>
  );
});

export const MeasurementOverlay = memo(MeasurementOverlayComponent);

export default MeasurementOverlay;

import type { SceneConfig } from '@/shared/types';
import { ProjectionMode } from '@/shared/types';
import { useLoader } from '@react-three/fiber';
import { useEffect, useMemo, useState } from 'react';
import type { Material, ShaderMaterial, Texture, VideoTexture } from 'three';
import { TextureLoader } from 'three';
import { useMaterialUpdater } from './useMaterialUpdater';
import { usePointCloudMaterial } from './usePointCloudMaterial';
import { useSceneMaterials } from './useSceneMaterials';

interface UseActiveMaterialOptions {
  activeMap: Texture | null;
  config: SceneConfig;
  displacementMap: Texture | null;
  seamCorrectionValue: number;
}

interface UseActiveMaterialReturn {
  activeMaterial: Material | ShaderMaterial | null;
}

export function useActiveMaterial(options: UseActiveMaterialOptions): UseActiveMaterialReturn {
  const { activeMap, displacementMap, config, seamCorrectionValue } = options;

  const pointCloudMaterial = usePointCloudMaterial();
  const materials = useSceneMaterials(activeMap, displacementMap!, config, seamCorrectionValue);
  let { activeMaterial } = materials;

  const isGaussianSplat = config.projectionMode === ProjectionMode.GAUSSIAN_SPLAT;

  if (isGaussianSplat && activeMap && displacementMap) {
    const { uniforms } = pointCloudMaterial;

    if (uniforms['map'] && uniforms['displacementMap'] && uniforms['displacementScale']) {
      uniforms['map']!.value = activeMap;
      uniforms['displacementMap']!.value = displacementMap;
      uniforms['displacementScale']!.value = config.displacementScale;
      activeMaterial = pointCloudMaterial;
    }
  }

  useMaterialUpdater({
    activeMaterial,
    animeMaterial: materials.animeMaterial,
    celMaterial: materials.celMaterial,
    crystalMaterial: materials.crystalMaterial,
    hologramV2Material: materials.hologramV2Material,
    inkWashMaterial: materials.inkWashMaterial,
    matrixMaterial: materials.matrixMaterial,
    retroPixelMaterial: materials.retroPixelMaterial,
  });

  return { activeMaterial: activeMaterial ?? null };
}

interface UseSceneTexturesOptions {
  backgroundUrl: string | null;
  depthUrl: string;
  emptyPixel: string;
  imageUrl: string;
  videoTextureRef: React.RefObject<VideoTexture | null>;
}

interface UseSceneTexturesReturn {
  activeMap: Texture | null;
  backgroundTexture: Texture;
  displacementMap: Texture;
  setVideoTexture: (texture: VideoTexture | null) => void;
}

export function useSceneTextures(options: UseSceneTexturesOptions): UseSceneTexturesReturn {
  const { imageUrl, depthUrl, backgroundUrl, emptyPixel, videoTextureRef } = options;

  const [colorMap, displacementMap, backgroundTexture] = useLoader(TextureLoader, [
    imageUrl,
    depthUrl,
    backgroundUrl ?? emptyPixel,
  ]);

  const [videoTexture, setVideoTexture] = useState<VideoTexture | null>(null);

  useEffect(() => {
    if (videoTextureRef) {
      videoTextureRef.current = videoTexture;
    }
  }, [videoTexture, videoTextureRef]);

  const activeMap = useMemo(() => videoTexture ?? colorMap ?? null, [videoTexture, colorMap]);

  return {
    activeMap,
    displacementMap: displacementMap!,
    backgroundTexture: backgroundTexture!,
    setVideoTexture,
  };
}

import {
  AlertCircle,
  Box,
  CheckCircle2,
  Clock,
  Cpu,
  FileImage,
  Loader2,
  RefreshCw,
  Scan,
  Settings,
  XCircle,
} from 'lucide-react';
import { memo, useEffect, useMemo, useState } from 'react';

import type { ProcessingState } from '@/shared/types';

interface StatusDisplayProps {
  onCancel?: () => void;
  onRetry: () => void;
  processingState: ProcessingState;
}

interface ProcessingStep {
  description: string;
  icon: React.ReactNode;
  id: string;
  label: string;
  status: 'pending' | 'active' | 'completed' | 'error';
}

// 预计处理时间（毫秒）
const ESTIMATED_TIMES: Record<string, number> = {
  analyzing: 2000,
  processing_depth: 5000,
  uploading: 1000,
};

export const StatusDisplay = memo(({ processingState, onRetry, onCancel }: StatusDisplayProps) => {
  const [elapsedTime, setElapsedTime] = useState(0);
  const startTime = useMemo(() => Date.now(), []);
  const [showDetails, setShowDetails] = useState(false);

  // 计算经过的时间
  useEffect(() => {
    const timer = setInterval(() => {
      setElapsedTime(Date.now() - startTime);
    }, 100);

    return () => clearInterval(timer);
  }, [startTime]);

  // 计算预计剩余时间
  const estimatedRemaining = useMemo(() => {
    const currentEstimate = ESTIMATED_TIMES[processingState.status] ?? 5000;
    const progress = processingState.progress / 100;
    const remaining = Math.max(0, currentEstimate * (1 - progress) - elapsedTime);

    return remaining;
  }, [processingState.status, processingState.progress, elapsedTime]);

  // 格式化时间
  const formatTime = (ms: number): string => {
    const seconds = Math.ceil(ms / 1000);

    if (seconds < 60) return `${seconds}秒`;
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;

    return `${minutes}分${remainingSeconds}秒`;
  };

  // 获取处理步骤
  const steps: ProcessingStep[] = useMemo(() => {
    const currentStatus = processingState.status;

    const getStepStatus = (stepId: string): ProcessingStep['status'] => {
      const stepOrder = ['upload', 'analyze', 'depth', 'scene'];
      const currentIndex = stepOrder.indexOf(
        currentStatus === 'uploading'
          ? 'upload'
          : currentStatus === 'analyzing'
            ? 'analyze'
            : currentStatus === 'processing_depth'
              ? 'depth'
              : 'scene'
      );
      const stepIndex = stepOrder.indexOf(stepId);

      if (stepIndex < currentIndex) return 'completed';
      if (stepIndex === currentIndex) return 'active';

      return 'pending';
    };

    return [
      {
        id: 'upload',
        label: '读取文件',
        description: '正在读取上传的文件数据',
        icon: <FileImage className="w-5 h-5" />,
        status: currentStatus === 'uploading' ? 'active' : 'completed',
      },
      {
        id: 'analyze',
        label: '分析媒体',
        description: '分析文件格式和内容',
        icon: <Scan className="w-5 h-5" />,
        status: getStepStatus('analyze'),
      },
      {
        id: 'depth',
        label: '深度估计',
        description: '使用AI生成深度图',
        icon: <Cpu className="w-5 h-5" />,
        status: getStepStatus('depth'),
      },
      {
        id: 'scene',
        label: '构建场景',
        description: '构建3D场景和材质',
        icon: <Box className="w-5 h-5" />,
        status: getStepStatus('scene'),
      },
    ];
  }, [processingState.status]);

  // 获取当前步骤索引
  const currentStepIndex = steps.findIndex((s) => s.status === 'active');

  // 处理中状态
  if (
    processingState.status === 'analyzing' ||
    processingState.status === 'processing_depth' ||
    processingState.status === 'uploading'
  ) {
    return (
      <div className="text-center z-10 w-full max-w-md mx-auto">
        <div className="bg-zinc-900/90 backdrop-blur-xl rounded-2xl border border-zinc-800 p-8 shadow-2xl">
          {/* 主进度 */}
          <div className="relative w-20 h-20 mx-auto mb-6">
            <div className="absolute inset-0 border-4 border-zinc-800 rounded-full" />
            <div
              className="absolute inset-0 border-4 border-cyan-500 border-t-transparent rounded-full animate-spin"
              style={{ animationDuration: '1.5s' }}
            />
            <div className="absolute inset-0 flex items-center justify-center">
              <span className="text-lg font-bold text-cyan-400">{processingState.progress}%</span>
            </div>
          </div>

          {/* 状态标题 */}
          <h3 className="text-xl font-semibold text-white mb-2">{processingState.message}</h3>
          <p className="text-sm text-zinc-400 mb-6">
            {estimatedRemaining > 0 && `预计剩余 ${formatTime(estimatedRemaining)}`}
          </p>

          {/* 处理步骤 */}
          <div className="space-y-3 mb-6">
            {steps.map((step) => {
              const isActive = step.status === 'active';
              const isCompleted = step.status === 'completed';

              return (
                <div
                  key={step.id}
                  className={`flex items-center gap-3 p-3 rounded-lg border transition-all ${
                    isActive
                      ? 'bg-cyan-950/30 border-cyan-500/30'
                      : isCompleted
                        ? 'bg-zinc-800/50 border-zinc-700/50'
                        : 'bg-zinc-900/50 border-zinc-800/30 opacity-50'
                  }`}
                >
                  <div
                    className={`${
                      isActive ? 'text-cyan-400' : isCompleted ? 'text-green-400' : 'text-zinc-500'
                    }`}
                  >
                    {isCompleted ? <CheckCircle2 className="w-5 h-5" /> : step.icon}
                  </div>
                  <div className="flex-1 text-left">
                    <div className="flex items-center justify-between">
                      <span
                        className={`text-sm font-medium ${
                          isActive
                            ? 'text-cyan-300'
                            : isCompleted
                              ? 'text-zinc-300'
                              : 'text-zinc-500'
                        }`}
                      >
                        {step.label}
                      </span>
                      {isActive && <Loader2 className="w-4 h-4 text-cyan-400 animate-spin" />}
                    </div>
                    <p className="text-xs text-zinc-500 mt-0.5">{step.description}</p>
                  </div>
                </div>
              );
            })}
          </div>

          {/* 进度条 */}
          <div className="w-full h-2 bg-zinc-800 rounded-full overflow-hidden mb-4">
            <div
              className="h-full bg-gradient-to-r from-cyan-500 to-blue-500 transition-all duration-500 ease-out"
              style={{ width: `${processingState.progress}%` }}
            />
          </div>

          {/* 统计信息 */}
          <div className="flex items-center justify-center gap-6 text-xs text-zinc-500">
            <div className="flex items-center gap-1">
              <Clock className="w-3.5 h-3.5" />
              <span>已用时 {formatTime(elapsedTime)}</span>
            </div>
            <div className="flex items-center gap-1">
              <span>
                步骤 {currentStepIndex + 1}/{steps.length}
              </span>
            </div>
          </div>

          {/* 取消按钮 */}
          {onCancel && (
            <div className="mt-6 pt-4 border-t border-zinc-800">
              <button
                type="button"
                className="flex items-center gap-2 px-4 py-2 mx-auto text-zinc-500 hover:text-red-400 hover:bg-red-950/30 rounded-lg transition-colors text-sm"
                onClick={onCancel}
              >
                <XCircle className="w-4 h-4" />
                取消处理
              </button>
            </div>
          )}
        </div>
      </div>
    );
  }

  // 错误状态
  if (processingState.status === 'error') {
    return (
      <div className="text-center max-w-md mx-auto">
        <div className="bg-zinc-900/90 backdrop-blur-xl rounded-2xl p-8 border border-red-500/30 shadow-2xl">
          <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-4">
            <AlertCircle className="w-8 h-8 text-red-500" />
          </div>

          <h3 className="text-xl font-semibold text-white mb-2">处理失败</h3>
